text:
&:disabled,
    &.is-disabled {
      background-color: xvar(
        --spectrum-high-contrast-gray-text,
        var(--spectrum-actionbutton-emphasized-background-color-selected-disabled)
      );
      border-color: xvar(
        --spectrum-high-contrast-gray-text,
        var(--spectrum-actionbutton-emphasized-border-color-selected-disabled)
      );
      color: xvar(
        --spectrum-high-contrast-button-face,
        var(--spectrum-actionbutton-emphasized-text-color-selected-disabled)
      );

      .spectrum-Icon {
        fill: xvar(
          --spectrum-high-contrast-button-face,
          var(--spectrum-actionbutton-emphasized-icon-color-selected-disabled)
        );
      }
    }

&:before {
  border-radius: calc(var(--spectrum-calendar-day-width) + var(--spectrum-alias-focus-ring-gap));
  content: '';
  display: block;
  position: absolute;
  top: calc(50% - calc(var(--spectrum-calendar-day-width) / 2));
  left: calc(50% - calc(var(--spectrum-calendar-day-width) / 2));
  width: calc(var(--spectrum-calendar-day-width) + var(--spectrum-alias-focus-ring-gap) * 2);
  height: calc(var(--spectrum-calendar-day-height) + var(--spectrum-alias-focus-ring-gap) * 2);
  margin: 0;
  transform: translateX(0); /* Forces FF to render on the pixel grid */

  transition:
    box-shadow var(--spectrum-global-animation-duration-100) ease-out,
    margin var(--spectrum-global-animation-duration-100) ease-out;
}

&.is-invalid {
	.spectrum-Checkbox-input:checked + .spectrum-Checkbox-box,
	.spectrum-Checkbox-box {
		&::before {
			border-color: var(--highcontrast-checkbox-color-default, var(--mod-checkbox-invalid-color-default, var(--spectrum-checkbox-invalid-color-default)));
		}
	}

	&.is-indeterminate .spectrum-Checkbox-input:focus-visible,
	.spectrum-Checkbox-input:focus-visible {
		& + .spectrum-Checkbox-box::before {
			border-color: var(--highcontrast-checkbox-color-hover, var(--mod-checkbox-invalid-color-hover, var(--spectrum-checkbox-invalid-color-hover)));
		}
	}

	&:hover {
		.spectrum-Checkbox-input:checked + .spectrum-Checkbox-box::before,
		.spectrum-Checkbox-box::before {
			border-color: var(--highcontrast-checkbox-color-hover, var(--mod-checkbox-invalid-color-hover, var(--spectrum-checkbox-invalid-color-hover)));
		}
	}
}

&.is-invalid.is-indeterminate {
	.spectrum-Checkbox-box,
	.spectrum-Checkbox-input:checked + .spectrum-Checkbox-box {
		&::before {
			border-color: var(--highcontrast-checkbox-color-default, var(--mod-checkbox-invalid-color-default, var(--spectrum-checkbox-invalid-color-default)));
			border-width: var(--mod-checkbox-selected-border-width, var(--spectrum-checkbox-selected-border-width));
		}
	}

	&:hover {
		.spectrum-Checkbox-box::before,
		.spectrum-Checkbox-input:checked + .spectrum-Checkbox-box::before {
			border-color: var(--highcontrast-checkbox-color-default, var(--mod-checkbox-invalid-color-hover, var(--spectrum-checkbox-invalid-color-hover)));
		}

		.spectrum-Checkbox-label {
			color: var(--highcontrast-checkbox-content-color-hover, var(--mod-checkbox-content-color-hover, var(--spectrum-checkbox-content-color-hover)));
		}
	}
}

&::before {
	forced-color-adjust: none;
	border-color: var(--highcontrast-checkbox-color-default, var(--mod-checkbox-control-color-default, var(--spectrum-checkbox-control-color-default)));

	display: block;
	z-index: 0;
	content: "";
	box-sizing: border-box;
	position: absolute;

	inline-size: var(--mod-checkbox-control-size, var(--spectrum-checkbox-control-size));
	block-size: var(--mod-checkbox-control-size, var(--spectrum-checkbox-control-size));

	border-radius: var(--mod-checkbox-control-corner-radius, var(--spectrum-checkbox-control-corner-radius));
	border-width: var(--mod-checkbox-border-width, var(--spectrum-checkbox-border-width));
	border-style: solid;

	transition:
		border var(--mod-checkbox-animation-duration, var(--spectrum-checkbox-animation-duration)) ease-in-out,
		box-shadow var(--mod-checkbox-animation-duration, var(--spectrum-checkbox-animation-duration)) ease-in-out;
}

%spectrum-ButtonWithFocusRing {
	&::after {
		content: "";

		position: absolute;
		inset-block-start: 0;
		inset-block-end: 0;
		inset-inline-start: 0;
		inset-inline-end: 0;

		display: block;

		margin: calc(-1 * var(--mod-button-focus-indicator-gap, var(--spectrum-focus-indicator-gap)));

		transition:
			opacity var(--mod-button-animation-duration, var(--mod-button-animation-duration, var(--spectrum-animation-duration-100))) ease-out,
			margin var(--mod-button-animation-duration, var(--mod-button-animation-duration, var(--spectrum-animation-duration-100))) ease-out;
	}

	&:focus-visible::after {
		margin: calc(-2 * var(--mod-focus-indicator-gap, var(--spectrum-focus-indicator-gap)));
	}
}

&.is-disabled {
	.spectrum-Dial-labelContainer {
		color: var(--highcontrast-dial-label-text-color-disabled, var(--mod-dial-label-text-color-disabled, var(--spectrum-dial-label-text-color-disabled)));
	}

	.spectrum-Dial-controls {
		&::after,
		&::before {
			background-color: var(--highcontrast-dial-handle-border-color-disabled, var(--mod-dial-handle-border-color-disabled, var(--spectrum-dial-handle-border-color-disabled)));
		}
	}

	.spectrum-Dial-handle {
		cursor: default;
		border-color: var(--highcontrast-dial-handle-border-color-disabled, var(--mod-dial-handle-border-color-disabled, var(--spectrum-dial-handle-border-color-disabled)));
		background: var(--mod-dial-background-color-default, var(--spectrum-dial-background-color-default));

		&::after,
		&::before {
			background-color: var(--highcontrast-dial-handle-border-color-disabled, var(--mod-dial-handle-border-color-disabled, var(--spectrum-dial-handle-border-color-disabled)));
		}
	}
}

&:focus-visible {
	background-color: var(--highcontrast-floating-action-button-background-color-key-focus, var(--mod-floating-action-button-background-color-key-focus, var(--spectrum-floating-action-button-background-color-key-focus)));
	outline: 0;

	.spectrum-FloatingActionButton-icon {
		fill: var(--highcontrast-floating-action-button-icon-color-key-focus, var(--mod-floating-action-button-icon-color-key-focus, var(--spectrum-floating-action-button-icon-color-key-focus)));
	}

	&::after {
		position: absolute;
		inset: 0;
		margin: calc(-1 * var(--mod-floating-action-button-focus-ring-gap, var(--spectrum-focus-indicator-gap)));
		box-shadow: 0 0 0 var(--mod-floating-action-button-focus-ring-width, var(--spectrum-focus-indicator-thickness)) var(--mod-afloating-action-button-focus-ring-color, var(--spectrum-focus-indicator-color));
		border-radius: var(--mod-floating-action-button-border-radius, 50%);
		pointer-events: none;
		content: "";
	}
}

@media (forced-colors: active) {
	.spectrum-Rating {
		--highcontrast-rating-icon-color-key-focus: CanvasText;
		--highcontrast-rating-icon-color-disabled: GrayText;
		--highcontrast-rating-emphasized-icon-color-default: Highlight;
		--highcontrast-rating-emphasized-icon-color-hover: Highlight;
		--highcontrast-rating-emphasized-icon-color-down: Highlight;
		--highcontrast-rating-focus-color-outline: CanvasText;

		&.is-focused {
			outline: 1px solid var(--highcontrast-rating-focus-color-outline);
		}

		&:hover .spectrum-Rating-icon.is-currentValue::after {
			background-color: var(--highcontrast-rating-icon-color-key-focus);
		}
	}

	.spectrum-Rating--emphasized:hover .spectrum-Rating-icon.is-currentValue::after {
		background-color: var(--highcontrast-rating-emphasized-icon-color-default);
	}
}

@container style(--system: legacy) {
	.spectrum-Slider {
		--spectrum-slider-track-color: var(--spectrum-gray-300);
		--spectrum-slider-ramp-track-color-disabled: var(--spectrum-gray-200);
		--spectrum-slider-ramp-handle-background-color: var(--spectrum-gray-100);
		--spectrum-slider-ticks-handle-background-color: var(--spectrum-gray-100);
		--spectrum-slider-handle-disabled-background-color: var(--spectrum-gray-100);
		--spectrum-slider-tick-mark-color: var(--spectrum-gray-300);
		--spectrum-slider-track-corner-radius: var(--spectrum-corner-radius-75);

		&,
		&.spectrum-Slider--sizeM {
			--spectrum-slider-handle-border-radius: var(--spectrum-corner-radius-200);
		}

		&.spectrum-Slider--sizeS {
			--spectrum-slider-handle-border-radius: var(--spectrum-corner-radius-200);
		}

		&.spectrum-Slider--sizeL {
			--spectrum-slider-handle-border-radius: calc(var(--spectrum-corner-radius-200) * 4);
		}

		&.spectrum-Slider--sizeXL {
			--spectrum-slider-handle-border-radius: calc(var(--spectrum-corner-radius-200) * 4);
		}
	}
}

@container style(--system: legacy) {
	.spectrum-Textfield {
		--spectrum-textfield-background-color: var(--spectrum-gray-50);
		--spectrum-textfield-background-color-disabled: var(--spectrum-disabled-background-color);

		--spectrum-textfield-border-color-disabled: var(--spectrum-gray-200);

		--spectrum-textfield-border-color-keyboard-focus: var(--spectrum-gray-900);

		--spectrum-textfield-icon-spacing-block-invalid: var(--spectrum-field-top-to-alert-icon-medium);

		&.spectrum-Textfield--sizeS {
			--spectrum-textfield-icon-spacing-block-invalid: var(--spectrum-field-top-to-alert-icon-small);
		}

		&.spectrum-Textfield--sizeL {
			--spectrum-textfield-icon-spacing-block-invalid: var(--spectrum-field-top-to-alert-icon-large);
		}

		&.spectrum-Textfield--sizeXL {
			--spectrum-textfield-icon-spacing-block-invalid: var(--spectrum-field-top-to-alert-icon-extra-large);
		}

		&.spectrum-Textfield--quiet {
			--spectrum-textfield-border-color-disabled: var(--spectrum-gray-300);
		}
	}
}
